import{r,o as l,a as d,b as e,d as o,w as i,F as p,e as t,c as a}from"./app.970ef970.js";import{_ as u}from"./plugin-vue_export-helper.21dcd24c.js";const c={},h=e("h1",{id:"agent-mode",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#agent-mode","aria-hidden":"true"},"#"),t(" Agent Mode")],-1),m=t("In version 1.102 of VS Code, Microsoft introduced "),f={href:"https://code.visualstudio.com/docs/copilot/chat/chat-agent-mode",target:"_blank",rel:"noopener noreferrer"},b=t("Agent Mode"),g=t(". Among other features, Agent Mode added support for the "),y={href:"https://code.visualstudio.com/docs/copilot/customization/mcp-servers",target:"_blank",rel:"noopener noreferrer"},w=t("Model Context Protocol (MCP)"),_=t(", which enables AI models used in VS\u202FCode access to external tool APIs and services. MCP is evolving into an open standard. It is implemented by many vendors and projects, and is supported by various AI clients such as "),v={href:"https://bob.ibm.com",target:"_blank",rel:"noopener noreferrer"},q=t("IBM Bob"),k=t(", VS Code's "),C={href:"https://marketplace.visualstudio.com/items?itemName=GitHub.copilot-chat",target:"_blank",rel:"noopener noreferrer"},x=t("GitHub Copilot Chat"),I=t(" and popular third-party VS Code extensions like "),M={href:"https://roocode.com",target:"_blank",rel:"noopener noreferrer"},P=t("Roo Code"),A=t("."),S=e("p",null,"The MCP protocol is implemented by VS Code, IBM Bob and many of its extensions as servers that provide access to data required by AI models to deliver accurate answers or to reach resources that are otherwise unavailable. Examples of MCP server functions include accessing your workspace files for review and modification, accessing your Git history to learn about recent changes and their reasons, and accessing resources on the internet, such as the latest documentation for tools and services that the AI model was not originally trained on. MCP tools can also perform active functions, such as executing VS Code tasks or running command-line operations in the terminal.",-1),O=e("p",null,[t("Z Open Editor adds its own set of MCP capabilities in the form of tools and resources that you can use with an AI chat. By leveraging Z Open Editor's Zowe APIs, the AI can interact with your z/OS system and access data sets, UNIX System Services files, and jobs. For example, you can ask the AI to list the members of a specific data set, fetch files that match a search pattern and compare them with files open in the current workspace, list your jobs and group them by status, or submit a new job using JCL that is selected in the editor or stored in a data set. In all cases, the AI displays the commands it intends to execute, shows the parameters, and requests your permission before proceeding. Another set of tools works with Z Open Editor's configuration files to help diagnose setup issues. You can ask the AI to check the editor's log file and ZAPP settings to determine why a copybook cannot be found for the currently open COBOL program. You can also inquire about your Zowe profiles and which defaults apply. Z Open Editor also provide MCP tools for its key integrations such as tools for IBM Dependency-Based Build and "),e("a",{href:"#configure-and-test-wazi-deploy-tools"},"IBM Wazi Deploy"),t(".")],-1),E=t("See the "),B=t("Z Open Editor MCP Reference"),z=t(" page for a list of currently available MCP tools and resources. This list expands with each release as new tools are added incrementally."),T=e("h2",{id:"how-to-use-agent-mode",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#how-to-use-agent-mode","aria-hidden":"true"},"#"),t(" How to use Agent Mode")],-1),Z=e("p",null,"As with any business use of AI, it is important to understand the implications. When you run MCP server tools and access resources, you grant the AI access to these data sources. This means content loaded from your z/OS system becomes available to the AI and is collected by the owners of the AI's language model. The AI can also create or delete files and data sets, execute jobs, and perform other operations.",-1),L=e("p",null,[e("strong",null,"It is therefore important to use these features only with AI setups that you trust and that are approved for use in your organization.")],-1),D=e("p",null,'It is recommended not to enable "auto approve" features, which enable MCP tools to perform operations without user confirmation, to avoid accidental loss of data. All tools and resources provided by Z Open Editor must be explicitly enabled before they can be used. Enable them only when the preceding preconditions are met.',-1),j=t("As a VS Code user, review the "),R={href:"https://code.visualstudio.com/docs/copilot/security",target:"_blank",rel:"noopener noreferrer"},V=t("Security"),G=t(" section in the VS Code documentation about Agent Mode, which describes additional potential security risks. If you use the IBM Bob IDE, review "),F={href:"https://bob.ibm.com/docs/ide/configuration/mcp/understanding-mcp",target:"_blank",rel:"noopener noreferrer"},U=t("this alternative page"),H=t(" for security information."),N=a('<p>The main switch for Z Open Editor&#39;s MCP feature is the user setting: <code>zopeneditor.mcp.enabled</code>. It is disabled by default.</p><p>The following sections outline setup steps for three alternative AI chat client solutions tested with Z Open Editor&#39;s MCP server. They describe the steps for using Z Open Editor MCP in</p><ul><li><a href="#setup-for-vs-code-with-github-copilot-chat">VS Code with GitHub Copilot Chat</a></li><li><a href="#setup-for-ibm-bob-ide">IBM Bob IDE</a></li><li><a href="#setup-for-vs-code-with-the-roo-code-vs-code-extension">VS Code with the Roo Code VS Code extension</a>.</li></ul><p>The Z Open Editor MCP tools also work with any other client that implements MCP and is used within an organization. Refer to the documentation for those client&#39;s for details on how to configure third-party MCP servers by using the &quot;http-streaming&quot; protocol.</p><h2 id="setup-for-vs-code-with-github-copilot-chat" tabindex="-1"><a class="header-anchor" href="#setup-for-vs-code-with-github-copilot-chat" aria-hidden="true">#</a> Setup for VS Code with GitHub Copilot Chat</h2>',5),Y=t("GitHub Copilot Chat is Microsoft\u2019s default AI\u2011chat solution for VS\u202FCode and enables Agent\u202FMode. It requires a GitHub account and a subscription after the free request limit or trial period ends. The extension can be configured to work with different large language models from a list of providers. Detailed setup instructions are available in the "),W={href:"https://code.visualstudio.com/docs/copilot/overview",target:"_blank",rel:"noopener noreferrer"},J=t("VS Code documentation"),Q=t("."),X=e("p",null,"Steps to enable and test Z Open Editor's MCP server:",-1),K=t("Install and configure the "),$={href:"https://marketplace.visualstudio.com/items?itemName=GitHub.copilot-chat",target:"_blank",rel:"noopener noreferrer"},ee=t("GitHub Copilot Chat"),te=t(" VS Code extension and sign in with your GitHub account."),oe=a(`<li><p>Ensure Agent Mode is enabled in VS Code with the user setting <code>chat.agent.enabled</code>.</p></li><li><p>In the Chat panel&#39;s lower-left corner, change the mode drop-down from its default &quot;Ask&quot; value to &quot;Agent&quot;.</p></li><li><p>In the model selection drop-down next to it, select the large language model you are authorized to use. Use the &quot;Manage Models..&quot; item for additional configuration options if necessary.</p></li><li><p>Load your source code workspace and create an MCP configuration file by adding an entry in the workspace&#39;s <code>.vscode/mcp.json</code> file. If you use a multi-root workspace or multiple editor windows, create one in each workspace you want to use, with unique name postfixes and port numbers to set the correct context for the AI. Alternatively, run the &quot;MCP: Add Server&quot; command to use prompts to create and edit the file.</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;servers&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;zopeneditor-sample&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span> <span class="token property">&quot;url&quot;</span><span class="token operator">:</span> <span class="token string">&quot;http://localhost:3005/mcp&quot;</span> <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></li><li><p>Ensure that the server name starts with <code>zopeneditor</code> followed by a workspace-specific prefix, as shown in the preceding example. This enables you and the AI to distinguish between different servers running in multiple workspaces. Each server you run in parallel requires a unique port number and name. Errors are shown in the Output panel called &quot;Z Open Editor MCP&quot; if a server cannot be started because its port is already in use.</p></li><li><p>Enable Z Open Editor&#39;s MCP server with the user setting: <code>zopeneditor.mcp.enabled</code>.</p></li><li><p>Reload the VS Code window to ensure all components are initialized and restarted.</p></li><li><p>Check the Z Open Editor output panel for an INFO message reporting that the MCP feature is enabled (search for message id &quot;CRRZG5452I&quot;).</p></li>`,8),se=t("Switch to the Z Open Editor MCP output panel and observe the startup messages in this view. It is recommended to set Z Open Editor's "),ae=t("logger to the DEBUG level"),ne=t(" to see more detailed information. The log should report that it found the mcp.json file and started the server using the information specified for the workspace in which is was found."),ie=a("<li><p>Switch back to the Chat panel in VS Code and click the tools icon at the bottom-right.</p></li><li><p>In the panel that appears at the top, the list of MCP tools is displayed. Below the &quot;Built-In&quot; section, locate the entry that matches the name of the server specified in the mcp.json file. Expand it to view all MCP tools provided by Z Open Editor.</p></li><li><p>Alternatively type <code>/list</code> in the Chat panel to obtain the list of tools in the Chat&#39;s output.</p></li><li><p>If the tools do not appear, check the Output panels again for any errors reported.</p></li><li><p>Execute any tool directly in the chat by using <code>#</code> with code completion on the tools list. For example, <code>#zowe-list-all-profiles</code> typed into the chat lists your profiles, assuming Zowe profiles defined.</p></li>",5),re=e("h2",{id:"setup-for-ibm-bob-ide",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#setup-for-ibm-bob-ide","aria-hidden":"true"},"#"),t(" Setup for IBM Bob IDE")],-1),le={href:"https://bob.ibm.com",target:"_blank",rel:"noopener noreferrer"},de=t("IBM Bob"),pe=t(" is IBM's AI-powered development partner. It comprises standalone editor clients that provide a VS Code look-and-feel as well as a terminal-centric shell. Both variants can be configured to work with Z Open Editor's MCP tools. For detailed documentation of Bob's MCP support, see "),ue={href:"https://bob.ibm.com/docs/ide/configuration/mcp/understanding-mcp",target:"_blank",rel:"noopener noreferrer"},ce=t("here for the IDE variant"),he=t(" and "),me={href:"https://bob.ibm.com/docs/shell/configuration/mcp/mcp-bobshell",target:"_blank",rel:"noopener noreferrer"},fe=t("here for the shell variant"),be=t("."),ge=e("p",null,"For both cases, a configuration file is needed to provide the details about Z Open Editor's MCP server to Bob. The format of these files is very similar to the VS Code MCP configuration file and almost identical to the Roo Code file described later in this section. Note that because Z Open Editor's MCP server runs as part of the Z Open Editor Bob/VS Code extension, you still must run a Bob IDE with the MCP configured if you want to utilize its MCP features in Bob Shell.",-1),ye=e("p",null,"Follow these setup steps:",-1),we=t("Install Z Open Editor into IBM Bob either through its integration with the "),_e={href:"https://open-vsx.org/extension/IBM/zopeneditor",target:"_blank",rel:"noopener noreferrer"},ve=t("Open-VSX Marketplace"),qe=t(" or manually using the extension file downloaded from our Mainframe Downloads Site as documented in "),ke=e("a",{href:"./getting_started"},"Getting Started",-1),Ce=t(". The installation process is identical to that for VS Code."),xe=a(`<li><p>Load your source code workspace and create a new MCP configuration file, or if already available, add an entry in the workspace&#39;s <code>.bob/mcp.json</code> file. As shown in the example later in this section, the location and format of the file differ slightly from those used for VS Code GitHub Chat. The name of the server contains the string &quot;zopeneditor&quot;. If you are using multiple workspaces either in a multi-root configuration or in multiple open editor windows, ensure that each has a unique name following &quot;zopeneditor-&quot; and port number listed in their file.</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;mcpServers&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;zopeneditor-sample&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
      <span class="token property">&quot;url&quot;</span><span class="token operator">:</span> <span class="token string">&quot;http://localhost:3005/mcp&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;streamable-http&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;timeout&quot;</span><span class="token operator">:</span> <span class="token number">600</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></li><li><p>Enable Z Open Editor&#39;s MCP server with the user setting: <code>zopeneditor.mcp.enabled</code>.</p></li><li><p>Reload the VS Code window to ensure all components are initialized and restarted.</p></li><li><p>From the IBM Bob Chat view, open the Bob Settings editor and switch to the &quot;MCP&quot; tab.</p></li><li><p>Ensure that the Z Open Editor MCP server is listed with the same name as specified in the configuration file.</p></li><li><p>Click the tile for Z Open Editor&#39;s MCP server. If you see the error &quot;fetch failed&quot;, click the refresh icon on the top-right of the editor. Clicking refresh might be necessary due to an open issue with Bob until it is fixed.</p></li><li><p>After the refresh, the complete list of MCP tools provided by Z Open Editor is displayed.</p></li><li><p>You can disable the tools that you do not want to use with slider buttons. Disabling tools helps you minimize token consumption when using Z Open Editor MCP tools as the MCP tool meta-data is provided as part of the AI chat&#39;s context window.</p></li><li><p>You can manage the &quot;Always allow&quot; state for each tool using the check boxes. Do not automatically allow any tools that perform write operations locally or on z/OS.</p></li><li><p>The results of these selection are appended to the <code>.bob/mcp.json</code> file and can be committed through Git for your workspace to be shared with your team members.</p></li><li><p>Ensure that you are running Bob in the &quot;Advanced Mode&quot;, which is the preferred mode for using MCP tools with Bob.</p></li>`,11),Ie=e("h2",{id:"setup-for-vs-code-with-the-roo-code-vs-code-extension",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#setup-for-vs-code-with-the-roo-code-vs-code-extension","aria-hidden":"true"},"#"),t(" Setup for VS Code with the Roo Code VS Code extension")],-1),Me={href:"https://roocode.com",target:"_blank",rel:"noopener noreferrer"},Pe=t("Roo Code"),Ae=t(" is gaining popularity as an alternative to GitHub Copilot Chat. It offers on-premises solutions with custom large language models, agentic multi-step tasks for larger workflows, and additional developer features such as workspace indexing."),Se=e("p",null,"To setup Z Open Editor's MCP with Roo Code",-1),Oe=t("Install the "),Ee={href:"https://marketplace.visualstudio.com/items?itemName=RooVeterinaryInc.roo-cline",target:"_blank",rel:"noopener noreferrer"},Be=t("Roo Code VS Code extension"),ze=t("."),Te=a(`<li><p>Configure your large language model by selecting a provider, entering API keys, and following the steps documented for Roo\u202FCode.</p></li><li><p>Load your source code workspace and create an MCP configuration file, or add an entry in the workspace&#39;s <code>.roo/mcp.json</code> file.</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token punctuation">{</span>
  <span class="token property">&quot;mcpServers&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
    <span class="token property">&quot;zopeneditor-sample&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
      <span class="token property">&quot;url&quot;</span><span class="token operator">:</span> <span class="token string">&quot;http://localhost:3005/mcp&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;type&quot;</span><span class="token operator">:</span> <span class="token string">&quot;streamable-http&quot;</span><span class="token punctuation">,</span>
      <span class="token property">&quot;timeout&quot;</span><span class="token operator">:</span> <span class="token number">600</span>
    <span class="token punctuation">}</span>
  <span class="token punctuation">}</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></li><li><p>Enable Z Open Editor&#39;s MCP server with the user setting: <code>zopeneditor.mcp.enabled</code>.</p></li><li><p>Reload the VS Code window to ensure all components are initialized and restarted.</p></li><li><p>At the top-right of the Roo Code chat panel, select the menu button (three dots) and choose &quot;MCP Servers&quot; item.</p></li><li><p>In the MCP Servers panel, verify that your &quot;zopeneditor&quot; server is listed. Use the Refresh buttons in the panel if it is not visible or is disabled.</p></li><li><p>After enabled, expand the &quot;zopeneditor&quot; entry to see all the MCP tools listed.</p></li><li><p>Close the panel with the &quot;Done&quot; button and start a chat.</p></li><li><p>Ask &quot;<em>List all Zowe profiles</em>&quot;. The chat prompts you to approve execution of the &quot;zowe-list-all-profiles&quot; MCP tool. After you click Approve, the list appears.</p></li>`,9),Ze=a(`<h2 id="configure-and-test-wazi-deploy-tools" tabindex="-1"><a class="header-anchor" href="#configure-and-test-wazi-deploy-tools" aria-hidden="true">#</a> Configure and test Wazi Deploy tools</h2><p>The Wazi Deploy Evidence MCP tools enables developers to query and analyze deployment evidence from z/OS systems through natural language prompts in Z Open Editor. These tools require some additional setup steps to the general steps listed above.</p><h3 id="prerequisites" tabindex="-1"><a class="header-anchor" href="#prerequisites" aria-hidden="true">#</a> Prerequisites</h3><p>Before testing, ensure the following:</p><ul><li>Wazi Deploy is installed on the target z/OS system.</li><li>A Zowe profile for this system is selected in the status bar as the default.</li><li>The <code>wazideploy-evidence</code> executable is available in the PATH (preferably at the beginning of the PATH), or the absolute path to its location is known.</li><li>A configured evidence <code>dataFolder</code>exists on your z/OS system and contains valid evidence files.</li></ul><p>In the Z Open Editor user settings, add values that match your Wazi Deploy configuration:</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token property">&quot;zopeneditor.wazideploy.evidence&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
  <span class="token property">&quot;dataFolder&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/u/ibmuser/projects/deploy/data&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;indexFolder&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/tmp/ibmuser_evidences_index&quot;</span><span class="token punctuation">,</span>
  <span class="token property">&quot;executablePath&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/global/opt/pyenv/gdp/bin/wazideploy-evidence&quot;</span><span class="token punctuation">,</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>These settings are also available in the Settings GUI under &quot;Zopeneditor &gt; Wazideploy: Evidence&quot;.</p><ul><li><strong>dataFolder</strong> (required) - Path to the directory containing valid evidence files.</li><li><strong>indexFolder</strong> (required) - Path to a writable directory for the evidence index.</li><li><strong>executablePath</strong> (optional) - Full path to the <code>wazideploy-evidence</code> executable. Use this only if the executable is not available in the system PATH or is located in a non-standard directory.</li></ul><p>When to use executablePath</p><ul><li>If <code>wazideploy-evidence</code> is not set or available in the PATH</li><li>If multiple versions exist and a specific one must be used</li><li>If installed in a custom or non-standard directory</li></ul><p>If <code>wazideploy-evidence</code> is already available in the PATH, this property can be omitted.</p><h3 id="first-time-setup" tabindex="-1"><a class="header-anchor" href="#first-time-setup" aria-hidden="true">#</a> First-Time Setup</h3><p>For initial setup, execute the following natural language prompts in your chat client:</p><p><strong>Prompt:</strong> &quot;Check Wazideploy evidence version&quot;</p><p>or run the <code>#wazideploy-check-version</code> MCP tool directly</p><p>The version check returns a version number (for example, 3.0.6) with a build date. Review the &quot;Z Open Editor MCP&quot; output view for logging information and errors if the expected result is not returned.</p><p><strong>Prompt:</strong> &quot;Index the Wazideploy evidence folder&quot;</p><p>or run the <code>#wazideploy-index-evidence-folder</code> MCP tool directly</p><p>The tool indexes the <code>dataFolder</code> successfully. Review the Output view for details of the operation and for troubleshooting information.</p><p><strong>Note:</strong> To get the &quot;type,&quot; evidences must be from version 3.0.7.1 or later; otherwise, you might see the &quot;none&quot; extension.</p><h3 id="natural-language-test-prompts" tabindex="-1"><a class="header-anchor" href="#natural-language-test-prompts" aria-hidden="true">#</a> Natural Language Test Prompts</h3>`,22),Le=t('After the index is created, run the following prompts in your chat client to confirm that the appropriate MCP tools are called. If the agent fails to match the MCP tools, add more context to the prompts (for example, include the word "wazideploy" or specify parameters explicitly). See the '),De=t("MCP Reference"),je=t(" for the complete list of tool and parameter names."),Re=a('<h4 id="environment-queries" tabindex="-1"><a class="header-anchor" href="#environment-queries" aria-hidden="true">#</a> Environment Queries</h4><ul><li>List all environments.</li><li>List environments with names ending in production.</li><li>List environments matching pattern <code>zos.*.integration</code>.</li><li>List environments where artifact XFRFUN is deployed.</li><li>List environments where artifact type CICSLOAD is deployed.</li><li>List environments deployed after 2025.</li><li>List environments deployed before 2025.</li><li>List environments including historical deployment records.</li></ul><h4 id="artifact-queries" tabindex="-1"><a class="header-anchor" href="#artifact-queries" aria-hidden="true">#</a> Artifact Queries</h4><ul><li>List all artifacts.</li><li>Show details for artifact XFRFUN.</li><li>List all artifacts of type DBRM.</li><li>List artifacts including historical records.</li><li>List artifacts deployed after 7 Aug 2025 and before last Sunday, including history.</li><li>List artifacts deployed after 20250807.144944 including history.</li></ul><h4 id="package-queries" tabindex="-1"><a class="header-anchor" href="#package-queries" aria-hidden="true">#</a> Package Queries</h4><ul><li>List all packages.</li><li>List packages including historical versions.</li><li>List packages deployed in production environments.</li><li>List packages deployed between January 2024 and December 2024.</li></ul><h4 id="failure-queries" tabindex="-1"><a class="header-anchor" href="#failure-queries" aria-hidden="true">#</a> Failure Queries</h4><ul><li>List all deployment failures.</li><li>List the latest 3 deployment failures.</li><li>Show all failures in the last 30 days.</li></ul><h4 id="field-value-queries" tabindex="-1"><a class="header-anchor" href="#field-value-queries" aria-hidden="true">#</a> Field Value Queries</h4><ul><li>List all possible values for the status field.</li><li>List all artifact names.</li><li>List all artifact types.</li><li>List all environment names.</li><li>List all package paths.</li></ul><h2 id="configure-dependency-based-build-dbb-tools" tabindex="-1"><a class="header-anchor" href="#configure-dependency-based-build-dbb-tools" aria-hidden="true">#</a> Configure Dependency Based Build (DBB) tools</h2><p>The MCP server holds tools for interacting with a remote DBB CLI for the purposes of troubleshooting pipeline builds. To use them, you need to follow the configuration steps listed here.</p><h3 id="prerequisites-1" tabindex="-1"><a class="header-anchor" href="#prerequisites-1" aria-hidden="true">#</a> Prerequisites</h3><h4 id="_1-install-dbb-on-a-remote-system" tabindex="-1"><a class="header-anchor" href="#_1-install-dbb-on-a-remote-system" aria-hidden="true">#</a> 1. Install DBB on a remote system</h4>',14),Ve=t("Install DBB using the documentation found at "),Ge={href:"https://www.ibm.com/docs/en/adffz/dbb/3.0.x?topic=installing-configuring-dbb",target:"_blank",rel:"noopener noreferrer"},Fe=t("Installing and configuring DBB"),Ue=t("."),He=e("h4",{id:"_2-create-a-db2\xAE-configuration-file",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_2-create-a-db2\xAE-configuration-file","aria-hidden":"true"},"#"),t(" 2. Create a Db2\xAE configuration file")],-1),Ne=e("p",null,[t("If you do not already have a Db2 configuration file, create one on your remote environment and store the URL to your Db2 JDBC metadata store inside of it. This is a Java "),e("code",null,".properties"),t(" file configured with a line similar to "),e("code",null,"url=jdbc:db2://example.com:5040/DBB1")],-1),Ye=e("h4",{id:"_3-create-a-db2-password-file",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#_3-create-a-db2-password-file","aria-hidden":"true"},"#"),t(" 3. Create a Db2 password file")],-1),We=t("If you do not already have a Db2 password file, create one on your remote environment. Learn how to do so in the DBB documentation on "),Je={href:"https://www.ibm.com/docs/en/adffz/dbb/3.0.x?topic=customization-encrypting-metadata-store-passwords",target:"_blank",rel:"noopener noreferrer"},Qe=t("Encrypting metadata store passwords"),Xe=t("."),Ke=a(`<h4 id="_4-configure-a-zowe-rse-profile" tabindex="-1"><a class="header-anchor" href="#_4-configure-a-zowe-rse-profile" aria-hidden="true">#</a> 4. Configure a Zowe RSE profile</h4><p>Configure a Zowe RSE profile that connects to your remote environment and set it as your default profile.</p><h3 id="first-time-setup-1" tabindex="-1"><a class="header-anchor" href="#first-time-setup-1" aria-hidden="true">#</a> First-Time Setup</h3><p>To use the tools that access a DBB metadata store like <code>dbb-get-build-result</code>, you must configure the following VSCode settings:</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token property">&quot;zopeneditor.dbb.metadataStore&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
 <span class="token property">&quot;db2User&quot;</span><span class="token operator">:</span> <span class="token string">&quot;USERNAME&quot;</span><span class="token punctuation">,</span>
 <span class="token property">&quot;db2Config&quot;</span><span class="token operator">:</span> <span class="token string">&quot;~/db2-metadata-store.properties&quot;</span><span class="token punctuation">,</span>
 <span class="token property">&quot;db2PasswordFile&quot;</span><span class="token operator">:</span> <span class="token string">&quot;~/encryptedPasswordFile.pw&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>This information is passed into the tool directly, so it is not seen by any AI agents that call it for privacy reasons.</p><p>If you include the <code>buildGroup</code> setting, the tool call uses it by default. If not, you must pass one to your agent when making the call.</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token property">&quot;zopeneditor.dbb.metadataStore&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
 <span class="token property">&quot;buildGroup&quot;</span><span class="token operator">:</span> <span class="token string">&quot;MortgageApplication-main&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If you include the <code>localAttachmentsDir</code> setting and call the <code>dbb-download-build-result-attachments</code> tool, the tool uses it by default. If not, you must pass one to your agent when making the call.</p><div class="language-json ext-json line-numbers-mode"><pre class="language-json"><code><span class="token property">&quot;zopeneditor.dbb.metadataStore&quot;</span><span class="token operator">:</span> <span class="token punctuation">{</span>
 <span class="token property">&quot;localAttachmentsDir&quot;</span><span class="token operator">:</span> <span class="token string">&quot;/path/to/create/local/dir&quot;</span>
<span class="token punctuation">}</span>
</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><h3 id="natural-language-test-prompts-1" tabindex="-1"><a class="header-anchor" href="#natural-language-test-prompts-1" aria-hidden="true">#</a> Natural Language Test Prompts</h3><h4 id="get-dbb-build-result" tabindex="-1"><a class="header-anchor" href="#get-dbb-build-result" aria-hidden="true">#</a> Get DBB Build Result</h4><ul><li>Get the DBB build result build-20260212.160108.068</li><li>Get the DBB build result build-20260212.160108.068 from group MortgageApplication-development.</li></ul><h4 id="get-last-failed-dbb-build-result" tabindex="-1"><a class="header-anchor" href="#get-last-failed-dbb-build-result" aria-hidden="true">#</a> Get Last Failed DBB Build Result</h4><ul><li>Get me my last failed build result.</li><li>Get me my last failed build result from group MortgageApplication-development.</li><li>Get me my last failed build result and tell me what went wrong with it.</li></ul><h4 id="download-all-the-attachments-of-a-dbb-build-result" tabindex="-1"><a class="header-anchor" href="#download-all-the-attachments-of-a-dbb-build-result" aria-hidden="true">#</a> Download all the attachments of a DBB build result</h4><ul><li>Download the attachments from build result build-20260212.160108.068</li><li>Get the attachments from build result build-20260212.160108.068 from group MortgageApplication-development.</li><li>Get the attachments from build result build-20260212.160108.068 and place it in ~/local/attachments/dir</li><li>Get the attachments from build result build-20260212.160108.068 from group MortgageApplication-main and place it in ~/local/attachments/dir</li></ul><h2 id="examples-of-using-the-mcp-tools" tabindex="-1"><a class="header-anchor" href="#examples-of-using-the-mcp-tools" aria-hidden="true">#</a> Examples of using the MCP tools</h2><p>After the MCP server starts, you can access it from the Chat panel. Refer to the Z Open Editor page for a list of available tools, you can combine them with tools from other MCP servers and with the built\u2011in tools. Here are few things you can try. Note, the responses you receive depend on the language model you use and on other factors.</p><p>Try some of the following examples, if a valid Zowe profile is configured in your workspace that can be used to access z/OS data sets, files, and jobs through Zowe Explorer. Replace the example names with your own.</p><ul><li><p>&quot;<em>List the members of the data set USER.SAMPLE.COBOL that start with the prefix SAM</em>&quot;. The AI prompts you for permission to execute the MCP tool &quot;zowe-get-members&quot; with the data set name you provided. After you approve the execution, the tool returns the list of members that start with SAM. Expand and examine the tool entry in the chat to see the full response. You see that the AI reduced the full list of members it received to the members that match the prefix.</p></li><li><p>Open a modified version of one of the programs listed in the previous step and ask &quot;<em>Download the member with the name SAM1 and compare to the currently open COBOL program in my editor.</em>&quot; The chat asks for approval to execute the &quot;zowe-download-member&quot; tool. After approval, the tool fetches the member and the AI provides a detailed explanation of the differences. The more the large language mode is trained on COBOL, the richer the explanation. If your are looking for a sample program, use the files &quot;COBOL/SAM1.cbl&quot; and &quot;multiroot/sam/SAM1.cbl&quot; from our <a href="./samplefiles">samples repository</a>. They are different versions of the same application.</p></li><li><p>&quot;<em>What are the jobs of user IBMUSER grouped by status?</em>&quot; The AI returns a list of job names organized in sections by status.</p></li><li><p>Use Zowe Explorer to open a JCL file from one of your data sets in Z Open Editor and ask &quot;<em>Submit the JCL in the currently open editor as a job.</em>&quot; It will prompt for approval of the &quot;zowe-submit-job-dataset&quot; tool with the correct data set name. If you would have opened a local file it would have used the tool &quot;zowe-submit-job-jcl&quot; instead. After it ran the command it will show you the job id, name, and status of your job. It might even ask you to retrieve the job output or current status.</p></li><li><p>Do retrieve the outputs from your job by replying &quot;<em>Yes, retrieve the spool files for me.</em>&quot; which will result into the list of files available, asking you which one you want to see. Reply with &quot;<em>Show me SYSOUT</em>&quot;, which it then retrieves and displays in the chat. If the output contained error messages, then some AI models will even explain the reasons for why things might have gone wrong. If you ask &quot;<em>Fetch SYSOUT and open it in a VS Code editor tab</em>&quot;, it would do that as well after asking you for permission, if it is allowed to save the content in a workspace file first.</p></li><li><p>&quot;<em>Fetch my .profile file from my UNIX home directory and open it in the editor. My userid is ibmuser.</em>&quot;. The AI deduces the home directory &quot;/u/ibmuser&quot;, asks for approval, downloads the file, and opens it in VS\u202FCode. If the deduction is incorrect, reject the request and refine the prompt with more specifics.</p></li></ul><p>In addition to Zowe interactions, you can use tools and resources provided by Z Open Editor&#39;s MCP server to query your configuration.</p>`,22),$e=a("<li><p>&quot;<em>List my Zowe profiles and the profiles defined as default for Z Open Editor.</em>&quot;. The AI executes two MCP tools, &quot;zowe-list-all-profiles&quot; and &quot;zopeneditor-get-default-zowe-profile&quot;, then lists all profiles found in your personal Zowe team configuration files together with the default profile used by Z\u202FOpen\u202FEditor.</p></li><li><p>&quot;<em>What are my ZAPP property groups for this workspace for COBOL and HLASM?</em>&quot;. AI calls &quot;zapp-get-property-groups&quot; twice and returns a summary for each language, assuming the property groups are defined in your ZAPP file.</p></li><li><p>Open a program where some copybooks cannot be found and ask: &quot;<em>Using the zopeneditor.log resource and the ZAPP property groups, analyze why copybook include files could not be found for the currently open program?</em>&quot; Depending on the language model, the AI automatically uses the MCP resource defined by Z Open Editor MCP or prompts you to execute the tool &quot;zopeneditor-read-the-log&quot; together with the previously retrieved ZAPP information. It then provides a detailed breakdown of the search process, listing locations that succeeded, locations that failed, and user settings that might have influenced the search.</p></li><li><p>To use the Z Open Editor log file as a resource in GitHub Chat, click the &quot;Add Context...&quot; button in the chat panel, select the file under &quot;MCP Resources&quot; in the prompt at the top of the screen, and confirm. The log file then appears next to the open program as context for your questions. You can use it to find various types of information from a DEBUG-level log file, such as details about your Zowe configuration, the version of Java used by the editor, user setting values, and more.</p></li>",4),et=t('Open a workspace that contains many COBOL files that must have sequence numbers added to them and ask: "'),tt=e("em",null,"Can you add sequence numbers to all the COBOL files matching the following pattern: COBOL/SOURCE/**",-1),ot=t(`". The files matching that pattern are then opened and have sequence numbers added to them. The changes are not saved by the tool to enable the user to confirm them. There are also tools to help if you'd like to remove sequence numbers or format a file instead, using your `),st=t("Z Code Format"),at=t(" file."),nt=t("You can also run "),it=t("ZCodeScan"),rt=t(' on many programs at once in your workspace using the same file patterns as shown above. "'),lt=e("em",null,"Run a scan of all the programs in the folder COBOL/SOURCE and describe the results in detail.",-1),dt=t(`" Z Open Editor's MCP tool finds all the programs in the folder or matches a provided pattern, runs a code scan on each, and then aggregates the results into one report. You can ask follow-up questions such as "`),pt=e("em",null,"Can you explain the first issue in more detail and provide examples for how to fix it?",-1),ut=t('" Many large language models then suggest how to perform the fix and guide you step-by-step.'),ct=a("<p>There are also tools available for COBOL and PL/I program analysis.</p><ul><li><p>Open a COBOL program and ask: &quot;<em>Using data flow information, what is the impact of increasing the length of CURRENT-YEAR from PIC 9(2) to PIC 9(4)?</em>&quot; The AI calls the data flow tool to trace where the data item is assigned, transformed, and referenced throughout the program. With that metadata, it estimates the scope of the change and recommends required modifications, reducing the risk of introducing truncation or format-related defects.</p></li><li><p>To analyze program structure, ask: &quot;<em>Using control flow information, which paragraphs call 730-READ-CUSTOMER-FILE and can this be optimized?</em>&quot; The AI calls the control flow tool to map how sections and paragraphs are connected across the program. This helps identify opportunities to simplify or streamline the program flow.</p></li></ul><p>You can combine Z\u202FOpen\u202FEditor\u2019s capabilities with the VS\u202FCode built\u2011in MCP tools listed earlier.</p><ul><li><p>If Z Open Editor reports syntax errors in your current program, you can use the integration with VS Code and its built-in MCP tools to resolve the issues reported in VS Code&#39;s Problems View. You can ask &quot;<em>Can you explain the issues listed in the Problems view for COBOL developers and suggest how to fix them?</em>&quot; If your large language model is trained on COBOL, it provides a detailed description of the problems found and suggests how to fix them.</p></li><li><p>&quot;<em>Who made the last few changes on this program looking at the Git history?</em>&quot;. The AI generates a command line that queries the local Git repository, retrieves recent commits, and displays their descriptions.</p></li><li><p>&quot;<em>Can you find other programs in the workspace that have the same ACCEPT-DATE and ACCEPT-TIME statements that need fixing?</em>&quot;. The AI uses the context of the previous interactions, runs a VS Code Search to find similar statements in other files in your workspace and lists the matching files with line numbers.</p></li><li><p>After you fixed the issues found by ZCodeScan you can ask to build the programs you fixed to ensure they still compile correctly with &quot;<em>Run a user build of the currently open program</em>&quot;.</p></li><li><p>If a DBB pipeline build (not a user build) fails on a remote machine, you can ask the AI to &quot;<em>get the last failed build result</em>&quot;. If the desired build result is not the most recent failure, you can ask it to &quot;<em>get the build result &lt;result-label&gt;</em>&quot;. You may have to configure settings to access your metadata store if you have not already done so.</p></li><li><p>If the error is not clear in the build result and information from the build logs would help with troubleshooting, you can ask it to &quot;<em>download the attachments of the build result that was just fetched</em>&quot;.</p></li></ul><p>As these examples demonstrate, a basic set of MCP tools can be used and combined in many ways, providing endless opportunities to make your development activities more productive. You no longer have to learn the syntax of complex Zowe CLI commands, search manually through large log files, or download, save, and compare files versions. Just ask the AI to do this for you. With many more tools on the horizon, IDz on VS Code seamlessly integrates into your AI workflows and use cases, delivering new capabilities as more tools become available.</p>",5);function ht(mt,ft){const s=r("ExternalLinkIcon"),n=r("RouterLink");return l(),d(p,null,[h,e("p",null,[m,e("a",f,[b,o(s)]),g,e("a",y,[w,o(s)]),_,e("a",v,[q,o(s)]),k,e("a",C,[x,o(s)]),I,e("a",M,[P,o(s)]),A]),S,O,e("p",null,[E,o(n,{to:"/Docs/mcp_tools.html"},{default:i(()=>[B]),_:1}),z]),T,Z,L,D,e("p",null,[j,e("a",R,[V,o(s)]),G,e("a",F,[U,o(s)]),H]),N,e("p",null,[Y,e("a",W,[J,o(s)]),Q]),X,e("ol",null,[e("li",null,[e("p",null,[K,e("a",$,[ee,o(s)]),te])]),oe,e("li",null,[e("p",null,[se,o(n,{to:"/Docs/locating_local_client_logs.html"},{default:i(()=>[ae]),_:1}),ne])]),ie]),re,e("p",null,[e("a",le,[de,o(s)]),pe,e("a",ue,[ce,o(s)]),he,e("a",me,[fe,o(s)]),be]),ge,ye,e("ol",null,[e("li",null,[e("p",null,[we,e("a",_e,[ve,o(s)]),qe,ke,Ce])]),xe]),Ie,e("p",null,[e("a",Me,[Pe,o(s)]),Ae]),Se,e("ol",null,[e("li",null,[e("p",null,[Oe,e("a",Ee,[Be,o(s)]),ze])]),Te]),Ze,e("p",null,[Le,o(n,{to:"/Docs/mcp_tools.html#wazi-deploy-evidence-tools"},{default:i(()=>[De]),_:1}),je]),Re,e("p",null,[Ve,e("a",Ge,[Fe,o(s)]),Ue]),He,Ne,Ye,e("p",null,[We,e("a",Je,[Qe,o(s)]),Xe]),Ke,e("ul",null,[$e,e("li",null,[e("p",null,[et,tt,ot,o(n,{to:"/Docs/zcodeformatting.html"},{default:i(()=>[st]),_:1}),at])]),e("li",null,[e("p",null,[nt,o(n,{to:"/Docs/advanced_zcodescan.html"},{default:i(()=>[it]),_:1}),rt,lt,dt,pt,ut])])]),ct],64)}var yt=u(c,[["render",ht]]);export{yt as default};
